INSERT INTO formations (id_formation, titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) SELECT gen_random_uuid(), v.* FROM (VALUES ('Management moderne & optimisation de la fonction secrétaire/assistant', 'Formation sur le rôle stratégique des assistants et secrétaires modernes.', 5, 100000.00, 'entreprise', '2026-06-15', 30, '2026-01-14 12:37:32', '2026-02-18 23:44:04', NULL, E'--- OBJECTIFS ---\n• Optimiser la gestion administrative et organisationnelle\n• Améliorer la communication interne et externe\n• Développer des compétences en planification et gestion des priorités\n• Utiliser des outils numériques pour accroître la productivité\n• Renforcer le rôle stratégique de l’assistant(e)/secrétaire dans l’entreprise\n• Professionnaliser la fonction support et accroître son impact\n\n--- OBJECTIFS DÉTAILLÉS ---\nComprendre les principes du management moderne et leur application, optimiser la gestion administrative et organisationnelle, améliorer la communication et la coordination, développer des compétences en planification et gestion des priorités, et utiliser des outils digitaux pour accroître l’efficacité.\n\n--- PRÉREQUIS ---\nExpérience préalable en secrétariat ou assistanat souhaitée. Connaissances de base en bureautique (Word, Excel, PowerPoint).\n\n--- CONTENU ---\nModule 1 : Introduction au management moderne\nModule 2 : Organisation et planification efficace\nModule 3 : Communication et coordination\nModule 4 : Gestion des documents et archivage\nModule 5 : Optimisation de la fonction d’assistant(e)/secrétaire\nModule 6 : Management du temps et productivité\nModule 7 : Compétences interpersonnelles et leadership\n\n--- NIVEAU ---\nTous niveaux\n\n--- PUBLIC ---\nAssistant(e)s de direction, secrétaires, adjoints administratifs, toute personne en charge du soutien administratif et organisationnel dans une entreprise.\n\n--- MÉTHODES ---\nPrésentations interactives, ateliers pratiques, mises en situation réelles, études de cas, jeux de rôle, évaluations formatives et feedback personnalisé.\n\n--- SUPPORTS ---\nOutils bureautiques (Word, Excel, PowerPoint), logiciels de gestion documentaire, calendriers partagés, outils cloud, supports PDF et modèles pratiques.\n\n--- CERTIFICATION ---\nAttestation de participation remise par ISD Groupe', 'ba52f30c-c061-41b8-b0f7-afa6eca6fa76')) AS v(titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) WHERE NOT EXISTS (SELECT 1 FROM formations f WHERE f.titre = v.titre AND f.date_debut = v.date_debut::date);
